// Generated by OrchestKit Claude Plugin
// Created: 2026-05-22

/**
 * Code Comment Glyph Warn — PostToolUse advisory linter.
 *
 * Flags emoji in code comments that are outside the visual-style.md
 * 12-glyph closed vocabulary. Advisory only — never blocks an Edit/Write.
 *
 * Rationale: per src/rules/visual-style.md, the "Code, commits, PR titles"
 * surface forbids emoji entirely. Code comments are part of that surface.
 * Catching them at write-time keeps the surface clean without adding
 * friction (warning, not block — reviewer can still catch in PR review).
 */

import type { HookInput, HookResult, HookContext } from '../types.js';
import { outputSilentSuccess, getField } from '../lib/common.js';
import { NOOP_CTX } from '../lib/context.js';

const HOOK_NAME = 'posttool/code-comment-glyph-warn';

// Closed vocabulary from src/rules/visual-style.md.
// Stored as Unicode codepoints to avoid file-encoding ambiguity.
const VOCAB_CODEPOINTS = new Set<number>([
  0x2705,    // white check mark
  0x274C,    // cross mark
  0x26A0,    // warning sign (base; VS16 0xFE0F may follow)
  0x1F504,   // anticlockwise arrows (refresh / loop)
  0x23F8,    // double vertical bar (pause)
  0x1F4A1,   // light bulb (hint)
  0x1F6A8,   // police car light (siren / critical)
  0x1F3AF,   // direct hit (target)
  0x1F525,   // fire
  0x1F4DC,   // scroll
  0x1F916,   // robot
  0x26A1,    // high voltage (lightning bolt)
  // Risk pair
  0x1F7E2,   // green circle
  0x1F7E1,   // yellow circle
  0x1F534,   // red circle
  // Ranking pair
  0x1F947,   // gold medal
  0x1F948,   // silver medal
  0x1F949,   // bronze medal
  // VS16 + ZWJ for combined emoji rendering
  0xFE0F,
  0x200D,
]);

// File extensions where comments are scanned. Markdown and prose
// formats are excluded — visual-style allows them in SKILL.md headings.
const CODE_EXTENSIONS = new Set([
  '.ts', '.tsx', '.js', '.jsx', '.mjs', '.cjs',
  '.py', '.go', '.rs', '.rb', '.java', '.kt',
  '.c', '.cpp', '.h', '.hpp', '.cs', '.swift',
  '.sh', '.bash', '.zsh',
]);

// Comment-line regex per language family. Conservative — only flags
// content that's clearly inside a comment (not, say, a string literal
// containing the substring "// ").
const COMMENT_PATTERNS: RegExp[] = [
  /^\s*\/\/.*$/m,    // C-family line comment
  /\/\*[\s\S]*?\*\//g, // C-family block comment
  /^\s*#(?!!).*$/m,  // Python/shell line comment (excludes shebang)
];

function extensionOf(path: string): string {
  const lastDot = path.lastIndexOf('.');
  if (lastDot < 0) return '';
  return path.slice(lastDot).toLowerCase();
}

function isCodeFile(path: string): boolean {
  return CODE_EXTENSIONS.has(extensionOf(path));
}

function extractCommentText(content: string): string {
  const out: string[] = [];
  for (const pattern of COMMENT_PATTERNS) {
    const matches = content.match(pattern);
    if (matches) out.push(...matches);
  }
  return out.join('\n');
}

function findNonVocabGlyphs(text: string): string[] {
  const found = new Set<string>();
  for (let i = 0; i < text.length; ) {
    const codepoint = text.codePointAt(i)!;
    const charLen = codepoint > 0xFFFF ? 2 : 1;
    // Detect emoji-like codepoints: in Symbol/Other category space.
    // 0x1F000+ catches most pictographs; 0x2600-0x27BF catches the
    // miscellaneous symbol blocks that the vocab draws from.
    const isEmojiLike =
      codepoint >= 0x1F000 ||
      (codepoint >= 0x2600 && codepoint <= 0x27BF);
    if (isEmojiLike && !VOCAB_CODEPOINTS.has(codepoint)) {
      found.add(String.fromCodePoint(codepoint));
    }
    i += charLen;
  }
  return [...found];
}

export function codeCommentGlyphWarn(
  input: HookInput,
  ctx: HookContext = NOOP_CTX,
): HookResult {
  const tool = input.tool_name || '';
  if (tool !== 'Edit' && tool !== 'Write') {
    return outputSilentSuccess();
  }

  const path = getField<string>(input, 'tool_input.file_path') || '';
  if (!path || !isCodeFile(path)) {
    return outputSilentSuccess();
  }

  // Extract the new content. Edit: new_string. Write: content.
  const newContent =
    tool === 'Write'
      ? getField<string>(input, 'tool_input.content') || ''
      : getField<string>(input, 'tool_input.new_string') || '';

  if (!newContent) return outputSilentSuccess();

  const commentText = extractCommentText(newContent);
  if (!commentText) return outputSilentSuccess();

  const violations = findNonVocabGlyphs(commentText);
  if (violations.length === 0) return outputSilentSuccess();

  ctx.log(HOOK_NAME, `Non-vocab glyphs in comments of ${path}: ${violations.join(' ')}`, 'debug');

  return {
    continue: true,
    systemMessage: `[visual-style] ⚠ Code comment in ${path} contains glyphs outside the 12-vocab: ${violations.join(' ')}. Per src/rules/visual-style.md the "code" surface forbids emoji. Advisory only — not a block.`,
  };
}

export default codeCommentGlyphWarn;
